# ── Constants ──────────────────────────────────────────────────────────────────

BASE_URL = "https://bey-library.vercel.app"
CRAWL_DELAY: float = 0.6       # polite pause between requests (seconds)
REQUEST_TIMEOUT: int = 20      # per-request socket timeout (seconds)

ALL_CATEGORIES: list[str] = [
    "blade",
    "over-blade",
    "assist-blade",
    "ratchet",
    "bit",
    "x-over",
    "other",
]

# Categories whose products are actual playable Beyblade parts (not accessories)
PLAYABLE: set[str] = {"blade", "over-blade", "assist-blade", "ratchet", "bit", "x-over"}

DEFAULT_OUTPUT = "beyblade_parts.csv"

# Spec keys that appear in concatenated spec text — longest first to avoid
# partial regex matches (e.g. "Weight" must not match inside "Burst Resistance")
_SPEC_KEYS: list[str] = [
    "Burst Resistance",
    "Stock Combo",
    "Product Line",
    "High Level",
    "Weight",
    "Gears",
    "Spin",
    "Type",
]

# Generated by GitHub Copilot
_SPEC_SPLIT_RE = re.compile(
    r"(" + "|".join(re.escape(k) for k in _SPEC_KEYS) + r")"
)

_PRODUCT_CODE_RE = re.compile(r"^(BX|UX|CX)[-\s](.*)$", re.IGNORECASE)
_CODE_BODY_RE = re.compile(r"^\s*(BX|UX|CX)-(\d+)\s*$", re.IGNORECASE)
_WEIGHT_RE = re.compile(r"~?([\d.]+)\s*[gG]\b")
_LEVEL_RE = re.compile(r"~?([\d.]+)\s*[mM][mM]")

# ── Data model ─────────────────────────────────────────────────────────────────

# Generated by GitHub Copilot
@dataclass
class BeyPart:
    """
    One row of the output CSV — one Beyblade X part or accessory.

    Category-specific columns that do not apply to a given part are left as
    empty strings so that downstream tools (pandas, Excel, etc.) treat them as
    null/NaN cleanly.
    """

    # --- Identity & classification ---
    part_id: str = ""              # URL slug, e.g. "Blade-DS-001"
    name: str = ""                 # Human-readable name, Title Case
    category: str = ""            # blade / ratchet / bit / over-blade / assist-blade / x-over / other
    is_beyblade_part: bool = True  # False for accessories (category == "other")
    product_code_full: str = ""   # Raw release code, e.g. "BX-01" or "Collab Star Wars"
    product_line: str = ""        # Parsed line: BX / UX / CX / Collab / 25th Anniversary …
    product_number: str = ""      # Numeric portion only, e.g. "01"; empty for special codes
    source_url: str = ""          # Canonical product page URL
    variant_count: int = 0        # Count of colour / recolour variants listed

    # --- Gameplay stats (shared across all playable categories) ---
    type: str = ""                # Attack / Defense / Stamina / Balance
    spin: str = ""                # Right / Left / Both
    weight_g: str = ""            # Normalised float string, e.g. "35.0"; empty when unknown

